function buildProfile(selectedBranches) {
    // Step 1-2: Find starting lenses
    const lensCounts = {};
    const axisCounts = {};
    const lokaCounts = {};

    selectedBranches.forEach(branch => {
        (branch.maps_to_lenses || []).forEach(lens => {
            lensCounts[lens] = (lensCounts[lens] || 0) + 1;
        });
        // axis comes from parent category
        axisCounts[branch.parent_axis] = (axisCounts[branch.parent_axis] || 0) + 1;
        lokaCounts[branch.parent_loka] = (lokaCounts[branch.parent_loka] || 0) + 1;
    });

    // Step 3: Sort by frequency
    const startLenses = Object.entries(lensCounts)
        .sort((a,b) => b[1]-a[1])
        .slice(0, 3)
        .map(e => e[0]);

    const dominantAxes = Object.entries(axisCounts)
        .sort((a,b) => b[1]-a[1])
        .slice(0, 2)
        .map(e => e[0]);

    // Step 4: Generate first quest
    const firstLens = startLenses[0];
    const firstQuest = matrixQuests[firstLens].levels['1'][0];

    return {
        startLenses,
        dominantAxes,
        verticalFocus: Object.entries(lokaCounts).sort((a,b) => b[1]-a[1])[0][0],
        firstQuest
    };
}
